def interval_intersection(intervals1, intervals2):
    result = []
    i, j = 0, 0
    while i < len(intervals1) and j < len(intervals2):
        start1, end1 = intervals1[i]
        start2, end2 = intervals2[j]

        # Calculate potential intersection
        intersect_start = max(start1, start2)
        intersect_end = min(end1, end2)

        # Check if there is an actual intersection (not just touching at a point)
        if intersect_start < intersect_end:
            result.append([intersect_start, intersect_end])

        # Move to the next interval
        if intersect_start == intersect_end:
            # Move to the next interval in the list
            if i < len(intervals1) - 1:
                i += 1
            else:
                break
        else:
            if intersect_start < end1:
                i += 1
            else:
                break
    return result
```

